/**
 * @param {number} n
 * @param {number} pos
 * @param {number} k
 * @return {number}
 */
function solve(n, pos, k) {
    const MOD = 1000000007n;

    // Number of people to the left of pos (indices 0 to pos-1)
    const leftCount = pos;
    // Number of people to the right of pos (indices pos+1 to n-1)
    const rightCount = n - 1 - pos;

    // The person at pos can choose 'L' or 'R' (2 options), which always contributes a factor of 2 to the final answer.
    // This choice does not affect the visibility count k.

    // The visibility count k is the sum of:
    // 1. Number of people to the left of pos who choose 'L'. (Let this be k_L)
    // 2. Number of people to the right of pos who choose 'R'. (Let this be k_R)
    // We need k_L + k_R = k.

    // For the left side (leftCount people):
    // A person i < pos is visible if they choose 'L'.
    // We need to choose exactly k_L people out of leftCount to choose 'L'.
    // The remaining leftCount - k_L people must choose 'R' (making them invisible).
    // The number of ways to achieve k_L is C(leftCount, k_L).

    // For the right side (rightCount people):
    // A person i > pos is visible if they choose 'R'.
    // We need to choose exactly k_R people out of rightCount to choose 'R'.
    // The remaining rightCount - k_R people must choose 'L' (making them invisible).
    // The number of ways to achieve k_R is C(rightCount, k_R).

    // Total ways for a fixed split (k_L, k_R) such that k_L + k_R = k:
    // Ways = C(leftCount, k_L) * C(rightCount, k_R)

    // We need to sum this over all valid k_L such that:
    // 0 <= k_L <= leftCount
    // 0 <= k_R <= rightCount  => 0 <= k - k_L <= rightCount
    // k - rightCount <= k_L <= k

    // Combining constraints on k_L:
    // max(0, k - rightCount) <= k_L <= min(k, leftCount)

    // Precompute combinations function (nCk)
    const MAX_N = n;
    const fact = new Array(MAX_N + 1);
    const invFact = new Array(MAX_N + 1);

    function power(base, exp) {
        let res = 1n;
        base %= MOD;
        while (exp > 0n) {
            if (exp % 2n === 1n) {
                res = (res * base) % MOD;
            }
            base = (base * base) % MOD;
            exp /= 2n;
        }
        return res;
    }

    function modInverse(n) {
        // Fermat's Little Theorem: a^(MOD-2) % MOD is the inverse of a mod MOD
        return power(n, MOD - 2n);
    }

    fact[0] = 1n;
    invFact[0] = 1n;
    for (let i = 1; i <= MAX_N; i++) {
        fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    }
    invFact[MAX_N] = modInverse(fact[MAX_N]);
    for (let i = MAX_N - 1; i >= 1; i--) {
        invFact[i] = (invFact[i + 1] * BigInt(i + 1)) % MOD;
    }

    function combinations(n, k) {
        if (k < 0 || k > n) {
            return 0n;
        }
        return (fact[n] * invFact[k] * invFact[n - k]) % MOD;
    }

    let totalWays = 0n;

    // Iterate over k_L, the number of visible people from the left side.
    const start_kL = Math.max(0, k - rightCount);
    const end_kL = Math.min(k, leftCount);

    for (let kL = start_kL; kL <= end_kL; kL++) {
        const kR = k - kL;

        // Ways to choose kL from leftCount
        const waysL = combinations(leftCount, kL);

        // Ways to choose kR from rightCount
        const waysR = combinations(rightCount, kR);

        // Total ways for this split (kL, kR)
        const currentWays = (waysL * waysR) % MOD;

        totalWays = (totalWays + currentWays) % MOD;
    }

    // The person at pos has 2 choices ('L' or 'R'), independent of the visibility count.
    const finalAnswer = (totalWays * 2n) % MOD;

    return Number(finalAnswer);
}

