      var b: Long = base % MOD
      var e: Long = exp
      while (e > 0) {
        if (e % 2 == 1) {
          res = (res * b) % MOD
        }
        b = (b * b) % MOD
        e /= 2
      }
      res
    }

    // Helper function for modular inverse using Fermat's Little Theorem
    def modInverse(n: Long): Long = power(n, MOD - 2)

    // Precompute factorials and inverse factorials
    val MAX_N = n.toInt
    val fact = Array.ofDim[Long](MAX_N + 1)
    val invFact = Array.ofDim[Long](MAX_N + 1)

